// Loop through incoming items to sanitize the raw email payload
for (const item of $input.all()) {
    let text = $('Gmail Trigger').first().json.text || "";// Fallback to empty string if missing

    // Regex patterns to strip historical email threads (LLM Token Optimization)
    const replyPatterns = [
        /^On.*wrote:/m,       // Standard English reply header
        /^Am.*schrieb:/m,     // Standard German reply header (DACH region support)
        /---Original Message---/i,
        /________________________________/
    ];

    let cleanedText = text;

    // Isolate the freshest message by truncating at the first reply pattern
    for (const pattern of replyPatterns) {
        const match = text.match(pattern);
        if (match && match.index > 0) {
            cleanedText = text.substring(0, match.index);
            break; 
        }
    }

    // Explicitly set the sanitized payload for the downstream LLM node
    item.json.cleaned_text = cleanedText.trim();
}

// Return the modified array
return $input.all();

