// 1. Preserve the AI's output so the Switch node still works
const aiData = $input.first().json;

// Extract the sender's actual email address and the subject safely using optional chaining
const toAddress = $('Gmail Trigger').first().json.from?.value?.[0]?.address || "";
let subject = $('Gmail Trigger').first().json.subject || "";

// Extract the RECEIVING email address (your inbox) to force the correct Gmail account
const dynamicEmail = $('Gmail Trigger').first().json.to?.value?.[0]?.address || "";

// Extract the AI's drafted reply safely (prevents crashing if AI formatting fails)
const rawDraft = aiData.output?.draft_reply || ""; 

// 2. Format the subject line as a Reply
if (subject && !subject.toLowerCase().startsWith('re:')) {
  subject = 'Re: ' + subject;
}

// 3. Clean up the AI Draft Formatting (Fixing the "Wall of Text")
// Convert literal \n strings into actual line breaks, ensuring it stays a string type
const cleanDraft = String(rawDraft).replace(/\\n/g, '\n');

// 4. Generate the smart Gmail Compose URL
const baseUrl = `https://mail.google.com/mail/u/${dynamicEmail}/?view=cm&fs=1`;

// Build URL: encode safely, and replace standard breaks (%0A) with Gmail's required breaks (%0D%0A)
const rejectUrl = `${baseUrl}&to=${encodeURIComponent(toAddress)}&su=${encodeURIComponent(subject)}&body=${encodeURIComponent(cleanDraft).replace(/%0A/g, '%0D%0A')}`;

// 5. Output the combined data (Original AI Data + The New URL)
return {
  ...aiData,
  reject_url: rejectUrl
};

